-- Type Class 定義
class Eq (A : Type) where {
  eq : A -> A -> Bool
}

-- Instance（where 語法）
instance eqBool : Eq Bool where {
  eq := fun a => fun b => match a with
    | true => b
    | false => not b
}

-- 繼承：Ord extends Eq
class Ord (A : Type) extends Eq where {
  compare : A -> A -> Bool
}

-- 帶繼承的 instance：必須同時提供 Eq 的 method
instance ordBool : Ord Bool where {
  eq := fun a => fun b => match a with
    | true => b
    | false => not b;
  compare := fun a => fun b => match a with
    | true => (match b with | true => false | false => false)
    | false => (match b with | true => true | false => false)
}

-- 隱式參數與 type class 配合
def isEq {A : Type} (inst : Eq A) (x : A) (y : A) : Bool :=
  Eq.eq {A} inst x y

-- rfl: goal 是 a ≡ a 時直接結束
theorem rfl_demo : add zero (succ zero) ≡ succ zero := by { rfl }

-- simp: 定義展開 + 化簡
theorem simp_demo (n : Nat) : add zero n ≡ n := by { simp }

-- rewrite: 用等式改寫 goal
-- addComm 已在 stdlib 中：addComm (m n : Nat) : add m n ≡ add n m
def n2 : Nat := succ (succ zero)
def n3 : Nat := succ (succ (succ zero))
theorem rw_demo : add n2 n3 ≡ add n3 n2 := by {
  rewrite (addComm n2 n3);
  exact refl
}

-- cases: 對值做分情況討論
theorem cases_demo (b : Bool) : not (not b) ≡ b := by {
  cases b;
  exact refl;
  exact refl
}

-- ring: Nat 算術自動化
theorem ring_demo : add zero zero ≡ zero := by { ring }

-- omega: 自然數線性算術
theorem omega_demo : add (succ zero) (succ zero) ≡ succ (succ zero) := by { omega }

-- 組合 tactic
theorem combo_demo (a : Bool) : or a false ≡ a := by {
  cases a;
  exact refl;
  exact refl
}

-- stdlib 已有 transportUa，這裡直接驗證

-- ua-β 是 refl：transport (ua e) x ≡ fst e x
-- 這在 Lean4 中不可能——ua 是 axiom，transport 會 stuck
theorem ua_beta_demo {A B : Type} (e : Equiv A B) (x : A)
  : transport (ua e) x ≡ fst e x := by { rfl }

-- 具體例子：Bool 上的 not 是等價
-- notEquiv : Equiv Bool Bool（已在 stdlib）
-- transport (ua notEquiv) true = not true = false
theorem transport_not_true : transport (ua notEquiv) true ≡ false := by { rfl }
theorem transport_not_false : transport (ua notEquiv) false ≡ true := by { rfl }

-- identity equivalence 的 transport 也能算
theorem transport_id_zero : transport (ua (idEquiv Nat)) zero ≡ zero := by { rfl }
theorem transport_id_bool : transport (ua (idEquiv Bool)) true ≡ true := by { rfl }

-- 甚至 Either 上也能算
theorem transport_id_either
  : transport (ua (idEquiv (Either Nat Bool))) (left zero : Either Nat Bool)
  ≡ (left zero : Either Nat Bool) := by { rfl }

-- transportRefl：沿常數路徑 transport 是恆等
theorem transport_const {A : Type} (a : A) : transport (fun i => A) a ≡ a := by { rfl }

